SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_acc_m_expire ON sc_acc_m_expire CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_acc_m_expire() RETURNS trigger AS $BODY$
BEGIN

  if coalesce(NEW.entry_id::text, '') = '' then
      NEW.entry_id := current_setting('app.login_id', true);
  end if;

  NEW.entry_date := statement_timestamp();

  if coalesce(NEW.branch_id::text, '') = '' then
      NEW.branch_id := current_setting('app.login_br', true);
  end if;


  if coalesce(NEW.status::text, '') = '' then
      NEW.status := '0';
  end if;


  if coalesce(NEW.last_cal_used::text, '') = ''   then
     NEW.last_cal_used := NEW.first_used_day;
  end if;

  if NEW.first_used_day = NEW.last_cal_used then
      NEW.balance := NEW.amount_value;
      NEW.first_expire_year  := 0;
  end if;

  if coalesce(NEW.accu_method::text, '') = ''   then
     NEW.accu_method := '0';
  end if;

 
  --แก้ไข ผู้เก็บ สถานที่เก็บ
  if (OLD.material_id IS NOT NULL AND OLD.material_id::text <> '' AND ( NEW.user_keep <> OLD.user_keep  
           or NEW.shelf_id <> OLD.shelf_id ))  then 
    --insert  sc_mem_edit_salary
    INSERT INTO sc_acc_m_expire_histroy( material_id,             seq_no,               shelf_id,   
             user_keep,               histroy_remark,       entry_id,   
             entry_date,              entry_client,         operate_date )  
    VALUES ( NEW.material_id,              null,                NEW.shelf_id,   
        NEW.user_keep,              NEW.remark,            null,   
        null,                         null,                   pka_dep.fp_deposit_date()  )    
;

             
  end if;
  
RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_acc_m_expire() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_acc_m_expire
	BEFORE INSERT OR UPDATE ON sc_acc_m_expire FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_acc_m_expire();

